#include<bits/stdc++.h>
using namespace std;
long long ans;
int main()
{
	int t;
	cin>>t;
	for(int i=0;i<t;i++){
		ans=0;
		int a;
		string s;
		cin>>a;
		cin>>s;
	//	reverse(s.begin(),s.end());
		
		for(long long j=0;j<s.size();j++){
			ans*=a;
			if(s[j]>='0'&&s[j]<='9')ans=ans+s[j]-'0';
			else ans=ans+(s[j]-'A'+10);
			//cout<<ans<<endl;
		}
		cout<<ans<<endl;
	}
	
 }
